const apiResponse = $('API: Player-Statistics').first().json;
const matchId = $('Webhook Player-Statistics').first().json.body.match_id;
if (!apiResponse.response || apiResponse.response.length === 0) return [];

return apiResponse.response.flatMap(teamData => {
  return teamData.players.map(playerData => {
    const p = playerData.player;
    const s = playerData.statistics[0];
    if (!s) return null;

    const g = s.games || {};
    const goals = s.goals || {};
    const passes = s.passes || {};
    const shots = s.shots || {};
    const tackles = s.tackles || {};
    const dribbles = s.dribbles || {};
    const fouls = s.fouls || {};
    const cards = s.cards || {};

    return {
      json: {
        match_id: matchId,
        team_external_id: teamData.team.id,
        player_external_id: p.id,
        position: g.position || null,
        minutes: g.minutes || 0,
        rating: g.rating ? parseFloat(g.rating) : null,
        shots_total: shots.total ?? null,
        shots_on_target: shots.on ?? null,
        goals: goals.total || 0,
        assists: goals.assists || 0,
        passes_total: passes.total ?? null,
        passes_key: passes.key ?? null,
        tackles_total: tackles.total ?? null,
        dribbles_attempts: dribbles.attempts ?? null,
        dribbles_success: dribbles.success ?? null,
        fouls_drawn: fouls.drawn ?? null,
        fouls_committed: fouls.committed ?? null,
        cards_yellow: cards.yellow || 0,
        cards_red: cards.red || 0
      }
    };
  }).filter(Boolean);
});
